import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Container, Row, Col, Card, Form, Button, Alert } from 'react-bootstrap';
import { useAuth } from '../contexts/AuthContext';
import { RegisterData } from '../types';

export const Register: React.FC = () => {
  const [formData, setFormData] = useState<RegisterData>({
    nombre: '',
    correo: '',
    password: '',
    password_confirm: '',
    telefono: '',
  });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [validated, setValidated] = useState(false);
  const [passwordStrength, setPasswordStrength] = useState({
    length: false,
    match: false,
  });

  const { register, isAuthenticated, loading, error } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (isAuthenticated) {
      navigate('/', { replace: true });
    }
  }, [isAuthenticated, navigate]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    // Validar contraseña en tiempo real
    if (name === 'password' || name === 'password_confirm') {
      const password = name === 'password' ? value : formData.password;
      const confirmPassword = name === 'password_confirm' ? value : formData.password_confirm;

      setPasswordStrength({
        length: password.length >= 8,
        match: password === confirmPassword && password.length > 0,
      });
    }
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const form = e.currentTarget;

    if (form.checkValidity() === false) {
      e.stopPropagation();
      setValidated(true);
      return;
    }

    if (formData.password !== formData.password_confirm) {
      return;
    }

    await register(formData);
  };

  const togglePassword = () => {
    setShowPassword(!showPassword);
  };

  const toggleConfirmPassword = () => {
    setShowConfirmPassword(!showConfirmPassword);
  };

  return (
    <div style={{ 
      background: '#f0f0e8', 
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      padding: '30px'
    }}>
      <Container>
        <Row className="justify-content-center">
          <Col md={8} lg={5}>
            <Card className="border-0" style={{ 
              borderRadius: '16px',
              boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
              overflow: 'hidden'
            }}>
              <div style={{
                background: '#6B8E6B',
                padding: '30px',
                textAlign: 'center'
              }}>
                <div style={{
                  width: '60px',
                  height: '60px',
                  background: 'white',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  margin: '0 auto 15px',
                  boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
                }}>
                  <i className="bi bi-person-plus" style={{ 
                    fontSize: '1.8rem', 
                    color: '#6B8E6B'
                  }}></i>
                </div>
                <h3 style={{ 
                  color: 'white', 
                  fontWeight: '600',
                  marginBottom: '5px',
                  fontSize: '1.5rem'
                }}>
                  Crear Cuenta
                </h3>
                <p className="mb-0" style={{ 
                  color: 'rgba(255,255,255,0.9)',
                  fontSize: '0.9rem'
                }}>
                  Unete a MuebleClick
                </p>
              </div>
              <Card.Body className="p-4">

                {error && (
                  <Alert variant="danger" className="mb-3" style={{ borderRadius: '8px' }}>
                    <i className="bi bi-exclamation-triangle me-2"></i> {error}
                  </Alert>
                )}

                <Form noValidate validated={validated} onSubmit={handleSubmit}>
                  <Row>
                    <Col md={6}>
                      <Form.Group className="mb-3" controlId="nombre">
                        <Form.Label style={{ color: '#5a5a5a', fontWeight: '500', fontSize: '0.85rem' }}>
                          Nombre Completo
                        </Form.Label>
                        <Form.Control
                          type="text"
                          name="nombre"
                          value={formData.nombre}
                          onChange={handleChange}
                          placeholder="Tu nombre"
                          required
                          style={{ 
                            borderRadius: '8px', 
                            padding: '10px 14px',
                            border: '1px solid #d0d0d0',
                            fontSize: '0.9rem'
                          }}
                        />
                      </Form.Group>
                    </Col>
                    <Col md={6}>
                      <Form.Group className="mb-3" controlId="telefono">
                        <Form.Label style={{ color: '#5a5a5a', fontWeight: '500', fontSize: '0.85rem' }}>
                          Telefono
                        </Form.Label>
                        <Form.Control
                          type="tel"
                          name="telefono"
                          value={formData.telefono}
                          onChange={handleChange}
                          placeholder="55-1234-5678"
                          style={{ 
                            borderRadius: '8px', 
                            padding: '10px 14px',
                            border: '1px solid #d0d0d0',
                            fontSize: '0.9rem'
                          }}
                        />
                      </Form.Group>
                    </Col>
                  </Row>

                  <Form.Group className="mb-3" controlId="correo">
                    <Form.Label style={{ color: '#5a5a5a', fontWeight: '500', fontSize: '0.85rem' }}>
                      Correo Electronico
                    </Form.Label>
                    <Form.Control
                      type="email"
                      name="correo"
                      value={formData.correo}
                      onChange={handleChange}
                      placeholder="tu@email.com"
                      required
                      style={{ 
                        borderRadius: '8px', 
                        padding: '10px 14px',
                        border: '1px solid #d0d0d0',
                        fontSize: '0.9rem'
                      }}
                    />
                  </Form.Group>

                  <Row>
                    <Col md={6}>
                      <Form.Group className="mb-3" controlId="password">
                        <Form.Label style={{ color: '#5a5a5a', fontWeight: '500', fontSize: '0.85rem' }}>
                          Contrasena
                        </Form.Label>
                        <Form.Control
                          type={showPassword ? 'text' : 'password'}
                          name="password"
                          value={formData.password}
                          onChange={handleChange}
                          placeholder="Minimo 8 caracteres"
                          required
                          minLength={8}
                          style={{ 
                            borderRadius: '8px', 
                            padding: '10px 14px',
                            border: '1px solid #d0d0d0',
                            fontSize: '0.9rem'
                          }}
                        />
                      </Form.Group>
                    </Col>
                    <Col md={6}>
                      <Form.Group className="mb-3" controlId="password_confirm">
                        <Form.Label style={{ color: '#5a5a5a', fontWeight: '500', fontSize: '0.85rem' }}>
                          Confirmar
                        </Form.Label>
                        <Form.Control
                          type={showConfirmPassword ? 'text' : 'password'}
                          name="password_confirm"
                          value={formData.password_confirm}
                          onChange={handleChange}
                          placeholder="Repite tu contrasena"
                          required
                          minLength={8}
                          style={{ 
                            borderRadius: '8px', 
                            padding: '10px 14px',
                            border: '1px solid #d0d0d0',
                            fontSize: '0.9rem'
                          }}
                        />
                      </Form.Group>
                    </Col>
                  </Row>

                  {/* Password validation */}
                  <div className="mb-3 p-2" style={{ 
                    background: '#f8f8f5', 
                    borderRadius: '8px',
                    border: '1px solid #e0e0e0'
                  }}>
                    <small style={{ color: '#5a5a5a', fontWeight: '500' }}>La contrasena debe tener:</small>
                    <div className="d-flex gap-4 mt-1">
                      <small className={passwordStrength.length ? 'text-success' : 'text-muted'} style={{ fontSize: '0.8rem' }}>
                        <i className={`bi ${passwordStrength.length ? 'bi-check-circle-fill' : 'bi-circle'}`}></i> Minimo 8 caracteres
                      </small>
                      <small className={passwordStrength.match ? 'text-success' : 'text-muted'} style={{ fontSize: '0.8rem' }}>
                        <i className={`bi ${passwordStrength.match ? 'bi-check-circle-fill' : 'bi-circle'}`}></i> Coincidir
                      </small>
                    </div>
                  </div>

                  <Form.Group className="mb-3" controlId="terminos">
                    <Form.Check 
                      type="checkbox" 
                      label={<span style={{ fontSize: '0.85rem' }}>Acepto los terminos y condiciones</span>}
                      required
                    />
                  </Form.Group>

                  <Button 
                    variant="primary" 
                    type="submit" 
                    className="w-100 mb-3"
                    disabled={loading}
                    style={{
                      borderRadius: '8px',
                      padding: '12px',
                      fontWeight: '500',
                      background: '#6B8E6B',
                      border: 'none',
                      fontSize: '0.95rem'
                    }}
                  >
                    {loading ? (
                      <>
                        <span className="spinner-border spinner-border-sm me-2"></span>
                        Creando cuenta...
                      </>
                    ) : (
                      <>Crear Cuenta</>
                    )}
                  </Button>
                </Form>

                <div className="text-center pt-3" style={{ borderTop: '1px solid #e0e0e0' }}>
                  <p className="mb-2" style={{ color: '#888', fontSize: '0.85rem' }}>Ya tienes una cuenta?</p>
                  <Button 
                    variant="outline-secondary" 
                    href="/login"
                    className="w-100"
                    style={{
                      borderRadius: '8px',
                      padding: '10px',
                      fontSize: '0.9rem',
                      border: '1px solid #d0d0d0'
                    }}
                  >
                    Iniciar Sesion
                  </Button>
                </div>
              </Card.Body>
            </Card>
          </Col>
        </Row>
      </Container>
    </div>
  );
};
